External knowledge: 
- Customer satisfaction rating refers to the average feedback rating provided by users; 
- Repaid loans refer to loans with a status of 'repaid', while active loans refer to loans with a status of 'active'.

sql:
SELECT due_date, amount_due
FROM loan_repayments
WHERE status = 'pending';

SELECT invitee_name
FROM user_invitations
WHERE status = 'accepted';

SELECT SUM(amount_due) as total_pending_amount
FROM loan_repayments
WHERE status = 'pending';

SELECT loan_id, rate, calculation_method,
       SUM(rate) OVER () AS total_interest_rate
FROM loan_interests;

SELECT SUM(rate) AS total_interest_rate, calculation_method, interest_frequency
FROM loan_interests
GROUP BY calculation_method, interest_frequency;
